            )
            return result.model_dump()

    except Exception as exc:
        logger.debug("Structured extraction skipped for %s: %s", doc_type, exc)
    return {}


# ---------------------------------------------------------------------------
# Connector
# ---------------------------------------------------------------------------

class DocumentConnector(BaseConnector):
    """Multi-format document connector using Docling + Gemini structured extraction."""

    source_type = "document"

    def __init__(self, extract_structured: bool = False):
        # Structured extraction costs Gemini API calls — opt-in
        self.extract_structured = extract_structured

    def fetch(self, path: Path) -> Iterator[dict]:
        """Yield raw extraction dicts. Path can be file or directory."""
        if path.is_dir():
            for ext in (*_DOCLING_EXTS, *_CSV_EXTS, *_TEXT_EXTS):
                for file in sorted(path.rglob(f"*{ext}")):
                    yield from self._process_file(file)
        elif path.is_file():
            yield from self._process_file(path)

    def _process_file(self, path: Path) -> Iterator[dict]:
        ext = path.suffix.lower()
        logger.debug("Processing %s", path)
        try:
            if ext in _DOCLING_EXTS:
                extracted = _extract_with_docling(path)
            elif ext in _CSV_EXTS:
                extracted = _extract_csv(path)
            elif ext in _TEXT_EXTS:
                extracted = _extract_text(path)
            else:
                return

            doc_type = _detect_doc_type(path)
            structured = {}
            if self.extract_structured and extracted.get("text"):
                structured = _extract_structured(extracted["text"], doc_type)

            yield {
                "_path": str(path),
                "_doc_type": doc_type,
                "_ext": ext,
                "text": extracted.get("text", ""),
                "tables": extracted.get("tables", []),
                "rows": extracted.get("rows", []),
                "structured": structured,
                "extraction_method": extracted.get("method", "unknown"),
            }
        except Exception as exc:
            logger.warning("Failed to process %s: %s", path, exc)

    def normalize(self, raw: dict) -> SourceRecord:
        path = Path(raw["_path"])
        doc_type = raw["_doc_type"]

        payload = {
            "file_name": path.name,
            "doc_type": doc_type,
            "extension": raw["_ext"],
            "text": raw.get("text", "")[:8000],  # cap for jsonb
            "structured": raw.get("structured", {}),
            "table_count": len(raw.get("tables", [])),
            "row_count": len(raw.get("rows", [])),
            "extraction_method": raw.get("extraction_method"),
        }

        content_hash = SourceRecord.hash_payload(payload)
        return SourceRecord(
            id=SourceRecord.make_id(f"doc_{doc_type}", content_hash),
            source_type=f"doc_{doc_type}",
            source_uri=str(path),
            source_native_id=path.stem,
            payload=payload,
            content_hash=content_hash,
            metadata={
                "method": raw.get("extraction_method", "docling"),
                "doc_type": doc_type,
                "file_size_bytes": path.stat().st_size if path.exists() else 0,
            },
        )

"""CRM connector — reads clients, vendors, customers, sales (HubSpot-shape mock)."""

from __future__ import annotations

import json
from pathlib import Path
from typing import Iterator

from server.connectors.base import BaseConnector, SourceRecord


class CRMConnector(BaseConnector):
    """Reads all CRM files from a directory: clients, vendors, customers, sales."""

    source_type = "crm_contact"

    _FILE_MAP = {
        "clients.json": "crm_client",
        "vendors.json": "crm_vendor",
        "customers.json": "crm_customer",
        "sales.json": "crm_sale",
        "products.json": "crm_product",
    }

    def fetch(self, path: Path) -> Iterator[dict]:
        """Path may be a directory (scans all CRM files) or a single JSON file."""
        if path.is_dir():
            for filename, record_type in self._FILE_MAP.items():
                target = path / filename
                if target.exists():
                    yield from self._load_file(target, record_type)
        else:
            record_type = self._FILE_MAP.get(path.name, "crm_record")
            yield from self._load_file(path, record_type)

    def _load_file(self, path: Path, record_type: str) -> Iterator[dict]:
        with open(path) as f:
            data = json.load(f)
        for record in (data if isinstance(data, list) else []):
            yield {"_record_type": record_type, "_source_file": str(path), **record}

    def normalize(self, raw: dict) -> SourceRecord:
        record_type = raw.pop("_record_type", "crm_record")
        source_file = raw.pop("_source_file", "crm")

        # Pick best native ID per record type
        native_id = (
            raw.get("client_id")
            or raw.get("customer_id")
            or raw.get("product_id")
            or str(raw.get("sales_record_id", ""))
            or raw.get("id", "")
        )

        payload = {k: v for k, v in raw.items()}
        content_hash = SourceRecord.hash_payload(payload)
        return SourceRecord(
            id=SourceRecord.make_id(record_type, content_hash),
            source_type=record_type,
            source_uri=source_file,
            source_native_id=native_id,
            payload=payload,
            content_hash=content_hash,
            metadata={"method": "connector_ingest"},
        )

"""HR connector — reads employees.json + resume_information.csv."""

from __future__ import annotations

import csv
import json
from pathlib import Path
from typing import Iterator

from server.connectors.base import BaseConnector, SourceRecord


class HRConnector(BaseConnector):
    source_type = "hr_record"

    def fetch(self, path: Path) -> Iterator[dict]:
        if path.is_dir():
            emp_file = path / "Employees" / "employees.json"
            if emp_file.exists():
                yield from self._load_employees(emp_file)
            resume_file = path / "Resume" / "resume_information.csv"
            if resume_file.exists():
                yield from self._load_resumes(resume_file)
        elif path.suffix == ".json":
            yield from self._load_employees(path)
        elif path.suffix == ".csv":
            yield from self._load_resumes(path)

    def _load_employees(self, path: Path) -> Iterator[dict]:
        with open(path) as f:
            for emp in json.load(f):
                yield {"_record_subtype": "employee", "_source_file": str(path), **emp}

    def _load_resumes(self, path: Path) -> Iterator[dict]:
        with open(path, newline="", encoding="utf-8") as f:
            for row in csv.DictReader(f):
                yield {"_record_subtype": "resume", "_source_file": str(path), **row}

    def normalize(self, raw: dict) -> SourceRecord:
        subtype = raw.pop("_record_subtype", "employee")
        source_file = raw.pop("_source_file", "hr")

        if subtype == "employee":
            native_id = raw.get("emp_id", "")
            payload = {
                "emp_id": raw.get("emp_id"),
                "name": raw.get("Name"),
                "email": raw.get("email"),
                "category": raw.get("category"),
                "level": raw.get("Level"),
                "salary": raw.get("Salary"),
                "doj": raw.get("DOJ"),
                "dol": raw.get("DOL"),
                "skills": raw.get("skills"),
                "reportees": raw.get("reportees", []),
                "performance_rating": raw.get("Performance Rating"),
            }
        else:  # resume
            native_id = raw.get("resume_id", raw.get("emp_id", ""))
            payload = {
                "resume_id": raw.get("resume_id"),
                "emp_id": raw.get("emp_id"),
                "name": raw.get("name"),
                "email": raw.get("email"),
                "category": raw.get("category"),
                "content": raw.get("content", "")[:4000],  # cap for jsonb
                "created_date": raw.get("created_date"),
            }

        content_hash = SourceRecord.hash_payload(payload)
        return SourceRecord(
            id=SourceRecord.make_id(f"hr_{subtype}", content_hash),
            source_type=self.source_type,
            source_uri=source_file,
            source_native_id=native_id,
            payload=payload,
            content_hash=content_hash,
            metadata={"method": "connector_ingest", "subtype": subtype},
        )

"""Read-only Cypher endpoint for the Neo4j projection (WS-5).

Exposes the three pre-baked demo queries from
`server.sync.neo4j_projection.DEMO_QUERIES`. Generic Cypher is intentionally
not accepted here — WS-4 owns the broader query API.

When the projection isn't configured (empty `NEO4J_URI`), the routes return
503 with an honest message so the rest of the app keeps running
Postgres-only.
"""

from __future__ import annotations

from typing import Any

from fastapi import APIRouter, HTTPException, Request

from server.sync.neo4j_projection import DEMO_QUERIES, Neo4jProjection

router = APIRouter(prefix="/query/cypher", tags=["cypher"])


def _projection(request: Request) -> Neo4jProjection:
    proj: Neo4jProjection | None = getattr(request.app.state, "projection", None)
    if proj is None:
        raise HTTPException(
            status_code=503,
            detail="Neo4j projection unavailable — running Postgres-only mode.",
        )
    return proj


@router.get("/_health")
async def health(request: Request) -> dict[str, Any]:
    proj: Neo4jProjection | None = getattr(request.app.state, "projection", None)
    if proj is None:
        return {"status": "down", "reason": "neo4j not configured"}
    return await proj.healthcheck()


@router.get("/demo")
async def list_demos() -> dict[str, list[str]]:
    return {"queries": list(DEMO_QUERIES.keys())}


@router.get("/demo/{name}")
async def run_demo(
    name: str,
    request: Request,
    from_id: str | None = None,
    to_id: str | None = None,
) -> dict[str, Any]:
    if name not in DEMO_QUERIES:
        raise HTTPException(
            status_code=404,
            detail=f"unknown demo query; available: {list(DEMO_QUERIES.keys())}",
        )
    proj = _projection(request)
    assert proj.driver, "projection driver missing"
    cypher = DEMO_QUERIES[name]
    params = {k: v for k, v in {"from_id": from_id, "to_id": to_id}.items() if v}
    async with proj.driver.session(database=proj.cfg.neo4j_database) as session:
        result = await session.run(cypher, params)
        rows = [r.data() async for r in result]
    return {"name": name, "rows": rows, "row_count": len(rows)}

